module top_module(
	input [5:0] x,
   input [3:0] shift,
   output reg [11:0] inverted_out
   );integer i;

always @(*) begin
	inverted_out[11:10] = 2'b10;
	inverted_out[9:6] = 4'bx;
	i = shift[3:1];
	case (shift[0])
		1'b0: inverted_out[5:0] = x << i;
		1'b1: inverted_out[5:0] = x >> i;
	endcase
end

endmodule
